const input = $input.first().json;
const ctx = $('Montar Prompt Diana').first().json;

if (input.error || !input.content) {
  return [{
    json: {
      ...ctx,
      mensagem: `Oi ${ctx.nome}! Tive uma instabilidade aqui. Como você está se sentindo após o procedimento? 😊`,
      acao: 'responder',
      etapa: ctx.sessao_fase,
      nota_feedback: null,
      comentario_feedback: null,
      interesse_reagendamento: false,
      encerrar_sessao: false,
      historicoAtualizado: ctx.historico,
      erro: true
    }
  }];
}

const rawText = input.content?.find(b => b.type === 'text')?.text ?? '{}';

let parsed;
try {
  const cleaned = rawText.replace(/```json?/g, '').replace(/```/g, '').trim();
  parsed = JSON.parse(cleaned);
} catch(e) {
  parsed = {
    mensagem: `Oi ${ctx.nome}! Pode repetir como você está se sentindo?`,
    acao: 'responder',
    etapa: ctx.sessao_fase,
    nota_feedback: null,
    comentario_feedback: null,
    interesse_reagendamento: false,
    encerrar_sessao: false
  };
}

const validAcoes = ['responder', 'passar_para_bia', 'escalar_humano', 'encerrar'];
if (!validAcoes.includes(parsed.acao)) parsed.acao = 'responder';

const historicoAtualizado = [...ctx.historico, { role: 'assistant', content: parsed.mensagem }];

return [{
  json: {
    telefone: ctx.telefone,
    nome: ctx.nome,
    remoteJid: ctx.remoteJid,
    instancia: ctx.instancia,
    timestamp: ctx.timestamp,
    messageId: ctx.messageId,
    intent: ctx.intent,
    sessao_id: ctx.sessao_id,
    sessao_fase: parsed.etapa ?? ctx.sessao_fase,
    procedimento_realizado: ctx.procedimento_realizado,
    agendamento_id: ctx.agendamento_id,
    mensagem: parsed.mensagem,
    acao: parsed.acao,
    etapa: parsed.etapa ?? 'checkin',
    nota_feedback: parsed.nota_feedback ?? null,
    comentario_feedback: parsed.comentario_feedback ?? null,
    interesse_reagendamento: parsed.interesse_reagendamento ?? false,
    encerrar_sessao: parsed.encerrar_sessao ?? false,
    historicoAtualizado,
    diana_raw: rawText
  }
}];

const { telefone, nome, remoteJid, instancia, timestamp, messageId,
        procedimento_realizado, mensagem, historicoAtualizado } = $input.first().json;

return [{
  json: {
    telefone, nome, remoteJid, instancia, timestamp, messageId,
    mensagem,
    acao: 'passar_para_bia',
    historicoAtualizado,
    encerrar_sessao: true,
    procedimento_interesse: procedimento_realizado,
    topico: 'reagendamento',
    contexto_bia: {
      telefone, nome, remoteJid, instancia, timestamp, messageId,
      texto: `Quero agendar continuação: ${procedimento_realizado}`,
      intent: 'AGENDAR'
    }
  }
}];

const input = $input.first().json;
const { telefone, nome, acao, etapa, historicoAtualizado,
        encerrar_sessao, sessao_id, timestamp } = input;

const agora = new Date().toLocaleString('pt-BR');
const statusSessao = (encerrar_sessao || acao === 'encerrar' || acao === 'passar_para_bia')
  ? 'encerrado'
  : 'ativo';
const historicoLimitado = (historicoAtualizado ?? []).slice(-16);

return [{
  json: {
    telefone, nome, timestamp, acao, etapa,
    mensagem: input.mensagem,
    remoteJid: input.remoteJid,
    instancia: input.instancia,
    sessao_id,
    nota_feedback: input.nota_feedback,
    interesse_reagendamento: input.interesse_reagendamento,
    sessao_update: {
      Agente: 'DIANA',
      Fase: etapa ?? acao,
      Historico: JSON.stringify(historicoLimitado),
      Dado_Temp: JSON.stringify({
        etapa,
        procedimento_realizado: input.procedimento_realizado,
        nota_feedback: input.nota_feedback,
        interesse_reagendamento: input.interesse_reagendamento
      }),
      Atualizado_Em: agora,
      Status: statusSessao
    }
  }
}];
